function solve(edges, online, k) {
    const n = online.length;
    const adj = new Map();
    for (const [u, v, cost] of edges) {
        if (!adj.has(u)) {
            adj.set(u, []);
        }
        adj.get(u).push([v, cost]);
    }

    const maxHeap = new MinPriorityQueue({
        priority: (item) => item.negMinCost
    });
    maxHeap.enqueue({ negMinCost: 0, totalCost: 0, node: 0 });

    let maxScore = -1;

    while (!maxHeap.isEmpty()) {
        const { negMinCost, totalCost, node: u } = maxHeap.dequeue().element;
        const currentMinCost = -negMinCost;

        if (u === n - 1) {
            if (totalCost <= k) {
                if (currentMinCost > maxScore) {
                    maxScore = currentMinCost;
                }
            }
            continue;
        }

        if (!adj.has(u)) continue;
        for (const [v, cost] of adj.get(u)) {
            if (!online[v] && v !== n - 1) {
                continue;
            }
            const newTotal = totalCost + cost;
            if (newTotal > k) {
                continue;
            }
            const newMin = currentMinCost === 0 ? cost : Math.min(currentMinCost, cost);
            maxHeap.enqueue({ negMinCost: -newMin, totalCost: newTotal, node: v });
        }
    }

    return maxScore;
}
